namespace sv_f4dad96d1e5d4108b57472e754aa0b62.Client.Models;

public sealed record ShipmentDetails(
    string TrackingNumber,
    string Status,
    string Location,
    DateTimeOffset EstimatedDelivery,
    IReadOnlyList<StatusUpdate> Updates);

public sealed record StatusUpdate(
    DateTimeOffset Timestamp,
    string Status,
    string Location);

using sv_f4dad96d1e5d4108b57472e754aa0b62.Client.Models;

namespace sv_f4dad96d1e5d4108b57472e754aa0b62.Client.Services;

public interface IShipmentService
{
    Task<ShipmentDetails?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using System.Net.Http.Json;
using sv_f4dad96d1e5d4108b57472e754aa0b62.Client.Models;

namespace sv_f4dad96d1e5d4108b57472e754aa0b62.Client.Services;

/// <summary>
/// WebAssembly-side implementation that calls the server API.
/// </summary>
public sealed class ShipmentHttpService(HttpClient http) : IShipmentService
{
    public async Task<ShipmentDetails?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await http.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
            return null;

        response.EnsureSuccessStatusCode();

        return await response.Content.ReadFromJsonAsync<ShipmentDetails>(ct);
    }
}

using sv_f4dad96d1e5d4108b57472e754aa0b62.Client.Models;
using sv_f4dad96d1e5d4108b57472e754aa0b62.Client.Services;

namespace sv_f4dad96d1e5d4108b57472e754aa0b62.Services;

/// <summary>
/// Server-side implementation that simulates a slow backend with seeded data.
/// </summary>
public sealed class ServerShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new ShipmentDetails(
            TrackingNumber: "PKG-001",
            Status: "In Transit",
            Location: "Chicago, IL",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 25, 17, 0, 0, TimeSpan.Zero),
            Updates:
            [
                new StatusUpdate(new DateTimeOffset(2026, 5, 19, 8, 0, 0, TimeSpan.Zero), "Picked Up", "New York, NY"),
                new StatusUpdate(new DateTimeOffset(2026, 5, 20, 14, 30, 0, TimeSpan.Zero), "In Transit", "Philadelphia, PA"),
                new StatusUpdate(new DateTimeOffset(2026, 5, 21, 9, 15, 0, TimeSpan.Zero), "In Transit", "Chicago, IL"),
            ]),
        ["PKG-002"] = new ShipmentDetails(
            TrackingNumber: "PKG-002",
            Status: "Delivered",
            Location: "San Francisco, CA",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 20, 12, 0, 0, TimeSpan.Zero),
            Updates:
            [
                new StatusUpdate(new DateTimeOffset(2026, 5, 17, 10, 0, 0, TimeSpan.Zero), "Picked Up", "Seattle, WA"),
                new StatusUpdate(new DateTimeOffset(2026, 5, 18, 16, 0, 0, TimeSpan.Zero), "In Transit", "Portland, OR"),
                new StatusUpdate(new DateTimeOffset(2026, 5, 19, 22, 0, 0, TimeSpan.Zero), "Out for Delivery", "San Francisco, CA"),
                new StatusUpdate(new DateTimeOffset(2026, 5, 20, 11, 45, 0, TimeSpan.Zero), "Delivered", "San Francisco, CA"),
            ]),
        ["PKG-003"] = new ShipmentDetails(
            TrackingNumber: "PKG-003",
            Status: "Processing",
            Location: "Dallas, TX",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 28, 18, 0, 0, TimeSpan.Zero),
            Updates:
            [
                new StatusUpdate(new DateTimeOffset(2026, 5, 21, 6, 0, 0, TimeSpan.Zero), "Label Created", "Dallas, TX"),
            ]),
    };

    public async Task<ShipmentDetails?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        // Simulate slow backend
        await Task.Delay(1500, ct);

        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_f4dad96d1e5d4108b57472e754aa0b62.Client.Models
@using sv_f4dad96d1e5d4108b57472e754aa0b62.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<Shipment> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment <strong>@TrackingNumber</strong>...</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-container">
        <p class="error-message">@_errorMessage</p>
        <button @onclick="RetryLoad">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="not-found">
        <p>Shipment <strong>@TrackingNumber</strong> was not found.</p>
    </div>
}
else
{
    <div class="shipment-details">
        <h2>Shipment @_shipment.TrackingNumber</h2>
        <dl>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>
            <dt>Location</dt>
            <dd>@_shipment.Location</dd>
            <dt>Estimated Delivery</dt>
            <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
        </dl>

        <h3>Status Updates</h3>
        <ul class="status-updates">
            @foreach (var update in _shipment.Updates)
            {
                <li>
                    <time datetime="@update.Timestamp.ToString("o")">@update.Timestamp.ToString("g")</time>
                    &mdash; <strong>@update.Status</strong> (@update.Location)
                </li>
            }
        </ul>
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    private ShipmentDetails? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request (handles navigation to a different tracking number)
        CancelPending();

        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _loading = true;
        _errorMessage = null;
        _shipment = null;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Request was intentionally cancelled — do nothing.
            return;
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException || ex.CancellationToken != ct)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task RetryLoad()
    {
        await LoadShipmentAsync();
    }

    private void CancelPending()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    public void Dispose()
    {
        CancelPending();
    }
}

